  method: 'POST', headers, body: JSON.stringify({
    message: 'IVX IA identity brain: name, owner, IVXHOLDINGS project & investment answers',
    tree: tree.sha, parents: [HEAD_SHA],
  }),
});
if (!newCommitRes.ok) { console.error('commit FAIL:', newCommitRes.status, await newCommitRes.text()); process.exit(1); }
const newCommit = await newCommitRes.json();
console.log('NEW_COMMIT_SHA:', newCommit.sha);

// 6. Update ref
const refRes = await fetch(`https://api.github.com/repos/${REPO}/git/refs/heads/main`, {
  method: 'PATCH', headers, body: JSON.stringify({ sha: newCommit.sha, force: false }),
});
if (!refRes.ok) { console.error('ref FAIL:', refRes.status, await refRes.text()); process.exit(1); }
console.log('PUSHED OK:', newCommit.sha.slice(0,7));
